void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <int N, typename F>
double benchmark_n(F func) {
  double times[N];
  for (int i = 0; i < N; i++) times[i] = func();
  std::sort(times, times + N);
  return times[N / 2];
}

template <typename T>
__device__ __forceinline__ T zero_val() {
  return (T)0;
}

template <typename T>
__device__ __forceinline__ T neg_one_val() {
  return (T)-1;
}

template <typename T>
__device__ __forceinline__ T add_val(T a, T b) {
  return a + b;
}

template <typename T>
__device__ __forceinline__ T mul_val(T a, T b) {
  return a * b;
}

template <typename T>
__device__ __forceinline__ T muladd_val(T a, T b, T c) {
  return a * b + c;
}

template <typename T>
__device__ __forceinline__ bool is_equal_val(T a, T b) {
  return a == b;
}

