}

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD,
          int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_kernel(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  const int stride =
      BLOCK_STRIDED ? (int)blockSize : (int)(blockSize * gridDim.x);
  const int idx = BLOCK_STRIDED
                      ? (int)(blockIdx.x * blockSize * ELEMENTS_PER_THREAD +
                              threadIdx.x)
                      : (int)(blockIdx.x * blockSize + threadIdx.x);
  const int big_stride = (int)(gridDim.x * blockSize * ELEMENTS_PER_THREAD);

  T tmps[ELEMENTS_PER_THREAD];
#pragma unroll
  for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = muladd_val(tmps[j], tmps[j], seed);
      }
    }

    T sum = zero_val<T>();
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = add_val(sum, mul_val(tmps[j], tmps[j + 1]));
    }

    if (is_equal_val(sum, neg_one_val<T>())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

__global__ void warmup_kernel(short seed, short* g_data) {
  const unsigned int blockSize = blockDim.x;
  const int idx = (int)(blockIdx.x * blockSize + threadIdx.x);
  short tmp = g_data[idx];
  short sum = (short)(tmp * 0 + seed - 1);
  if (sum == (short)-1) g_data[idx] = sum;
}

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD,
          int FUSION_DEGREE, bool BLOCK_STRIDED>
double launch_kernel_once(T* d_data,
                          long size,
                          size_t workgroupsize,
                          bool use_os_timer,
                          T seed) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const dim3 dimBlock((unsigned int)workgroupsize);
  const dim3 dimGrid((unsigned int)(compute_grid_size / (long)workgroupsize));

  if (use_os_timer) {
    auto ts_start = std::chrono::steady_clock::now();
    benchmark_kernel<T, COMPUTE_ITERATIONS, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     BLOCK_STRIDED><<<dimGrid, dimBlock>>>(seed, d_data);
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
    auto ts_end = std::chrono::steady_clock::now();
    return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
  } else {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    benchmark_kernel<T, COMPUTE_ITERATIONS, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     BLOCK_STRIDED><<<dimGrid, dimBlock>>>(seed, d_data);
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float time_ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&time_ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    return (double)time_ms;
  }
}

void launch_warmup(short* d_data, long size, size_t workgroupsize) {
  const long reduced_grid_size = size / 256;
  const dim3 dimBlock((unsigned int)workgroupsize);
  const dim3 dimGrid((unsigned int)(reduced_grid_size / (long)workgroupsize));
  const short seed = 1;
  warmup_kernel<<<dimGrid, dimBlock>>>(seed, d_data);
  CUDA_SAFE_CALL(cudaGetLastError());
}

