template <typename T>
double dispatch_typed_kernel(int current_compute_iterations,
                             T* d_data,
                             long size,
                             size_t workgroupsize,
                             bool use_os_timer,
                             T seed) {
  switch (current_compute_iterations) {
#define DISPATCH_CASE(N)                                                       \
  case N:                                                                      \
    return launch_kernel_once<T, N, (int)kElementsPerWI, (int)kFusionDegree,   \
                              kBlockStrided>(d_data, size, workgroupsize,      \
                                             use_os_timer, seed);
    FOR_EACH_COMPUTE_ITERATION(DISPATCH_CASE)
#undef DISPATCH_CASE
    default:
      return 0.0;
  }
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              double* d_buffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer,
              bool enable_dp,
              bool enable_hp) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) *
           (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  double kernel_time_mad_sp = benchmark_n<3>([&]() {
    const float seed_f = 1.0f;
    return dispatch_typed_kernel<float>(
        current_compute_iterations, reinterpret_cast<float*>(d_buffer), size,
        workgroupsize, use_os_timer, seed_f);
  });

  double kernel_time_mad_dp = benchmark_n<3>([&]() {
    const double seed_d = 1.0;
    if (enable_dp) {
      return dispatch_typed_kernel<double>(
          current_compute_iterations, reinterpret_cast<double*>(d_buffer), size,
          workgroupsize, use_os_timer, seed_d);
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_hp = benchmark_n<3>([&]() {
    const __half2 seed_h = __float2half2_rn(1.0f);
    if (enable_hp) {
      return dispatch_typed_kernel<__half2>(
          current_compute_iterations, reinterpret_cast<__half2*>(d_buffer), size,
          workgroupsize, use_os_timer, seed_h);
    } else {
      return 0.0;
    }
  });

  double kernel_time_mad_int = benchmark_n<3>([&]() {
    const int seed_i = static_cast<int>(1.0);
    return dispatch_typed_kernel<int>(
        current_compute_iterations, reinterpret_cast<int*>(d_buffer), size,
        workgroupsize, use_os_timer, seed_i);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
  printf("Workgroup size:         %d\n", (int)kWorkgroupSize);
  printf("Elements per workitem:  %d\n", kElementsPerWI);
  printf("Workitem fusion degree: %d\n", kFusionDegree);

  const char* benchtype = kBlockStrided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      kHostAllocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         kUseOSTimer ? "OS based" : "CL event based");

  cudaDeviceProp deviceProp = GetDeviceProperties();
  if ((size_t)deviceProp.maxThreadsPerBlock < kWorkgroupSize) {
    fprintf(stderr, "Error: Unsupported workgroup size (%u).\n",
            (unsigned)kWorkgroupSize);
    exit(1);
  }

  bool enable_dp =
      (deviceProp.major > 1) || (deviceProp.major == 1 && deviceProp.minor >= 3);
  if (!enable_dp) {
    printf(
        "Warning:                Double precision computations are not "
        "supported\n");
  }

  bool enable_hp = IsFP16Supported();
  if (!enable_hp) {
    printf(
        "Warning:                Half precision computations are not "
        "supported\n");
  }

  double* d_buffer = NULL;
  CUDA_SAFE_CALL(cudaMalloc((void**)&d_buffer, size * sizeof(double)));

  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, size * sizeof(int)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  launch_warmup(reinterpret_cast<short*>(d_buffer), size, kWorkgroupSize);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  printf(
      "------------------------------------------------------------------------"
      "----- CSV data "
      "------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, d_buffer, size, kWorkgroupSize,
             kElementsPerWI, kFusionDegree, kUseOSTimer, enable_dp, enable_hp);
  }

  printf(
      "------------------------------------------------------------------------"
      "------------------------------------------------------------------------"
      "--------------------\n");

  CUDA_SAFE_CALL(
      cudaMemcpy(c, d_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));

  CUDA_SAFE_CALL(cudaFree(d_buffer));
}
